// // This module is designed to capture a single bit input (D) on the falling edge of the clock (Clk), and propagate it through three successive registers.
module top_module(
    input D, Clk,
    output reg Qa, Qb, Qc
    );always @(posedge Clk) begin
        Qa <= D;
        Qb <= Qa;
        Qc <= Qb;
    end

endmodule
